import xml.etree.ElementTree as ET
import sys
import os
from pathlib import Path
from summary import Summariser
import security

def is_stdlib(module):

    return module in sys.stdlib_module_names

def _out_path(filename):
    return  Path(os.getcwd())/filename

def gen_struct(extracted,reponame):
    root = ET.Element("repo",{"n":str(reponame)})
    meta = ET.SubElement(root,"meta")
    deps = ET.SubElement(meta,"dep")
    imports=[]
    pathstem=[]


    for file in extracted:
        if file.get('Fallback'):
            continue
        pathstem.append(Path(file["file_name"]).stem)

    for file in extracted:
        if file.get('Fallback'):
            continue
        for dep in file["imports"]:
            module = dep.split(".")[0]
            if not is_stdlib(module) and module not in pathstem and module not in imports:
                imports.append(module)

    deps.text = ",".join(imports)

    files = ET.SubElement(root,"files")

    for file in extracted:
        if file.get('Fallback'):
            continue
        f = ET.SubElement(files,"f",{"p":file["file_name"],"e":file["ext"]})

        if file["imports"]:
                imp = ET.SubElement(f,"imp")
                imp.text = ",".join(file["imports"])

        if file["functions"]:
            for func in file["functions"]:
                fn = ET.SubElement(f,"fn",{"n":func["name"],"p":func["params"]})

        if file["classes"]:
            for clas in file["classes"]:
                cls = ET.SubElement(f,"cls",{"n":clas})
                for func in file["classes"][clas]:
                    fn = ET.SubElement(cls,"fn",{"n":func["name"],"p":func["params"]})

        if file["struct"]:
            struct = ET.SubElement(f,"struct",{"n":file["struct"]})

        if file["enum"]:
            enum = ET.SubElement(f,"enum",{"n":file["enum"]})


    out = _out_path("structure.xml")
    tree = ET.ElementTree(root)
    ET.indent(tree)
    tree.write(str(out), encoding="utf-8", xml_declaration=True)
    return out.resolve()


def gen_summ(extracted, reponame):
    summariser = Summariser()
    root = ET.Element("repo", {"n": str(reponame)})
    meta = ET.SubElement(root, "meta")
    deps = ET.SubElement(meta, "dep")
    imports = []
    pathstem = []
    filenames = []

    for file in extracted:
        if file.get('Fallback'):
            continue
        filenames.append(Path(file["file_name"]))
        pathstem.append(Path(file["file_name"]).stem)

    for file in extracted:
        if file.get('Fallback'):
            continue
        for dep in file["imports"]:
            module = dep.split(".")[0]
            if not is_stdlib(module) and module not in pathstem and module not in imports:
                imports.append(module)

    deps.text = ",".join(imports)
    s = summariser.summarise_repo(reponame, imports, files=filenames)
    root.set("s", s)

    # ── build batch input ─────────────────────────────────────────────────
    files_data = []
    valid_files = []

    for file in extracted:
        if file.get('Fallback'):
            continue
        files_data.append({
            "path":      file["file_name"],
            "lang":      file["ext"],
            "imports":   file["imports"],
            "classes":   file["classes"],
            "functions": file["functions"],
        })
        valid_files.append(file)

    # ── batched summarisation with live spinner ───────────────────────────
    BATCH_SIZE = 20
    all_summaries = []

    try:
        import cli
        with cli.summary_progress_context(len(files_data)) as advance:
            for i in range(0, len(files_data), BATCH_SIZE):
                chunk = files_data[i : i + BATCH_SIZE]
                batch_summaries = summariser.summarise_files_batch(chunk)
                all_summaries.extend(batch_summaries)
                advance(
                    len(chunk),
                    label=f"batch {i // BATCH_SIZE + 1} / {((len(files_data) - 1) // BATCH_SIZE) + 1}"
                )
    except ImportError:
        # no UI — run silently
        for i in range(0, len(files_data), BATCH_SIZE):
            chunk = files_data[i : i + BATCH_SIZE]
            all_summaries.extend(summariser.summarise_files_batch(chunk))

    # ── build XML ─────────────────────────────────────────────────────────
    files_el = ET.SubElement(root, "files")

    for file, fs in zip(valid_files, all_summaries):
        mod = []
        f = ET.SubElement(files_el, "f", {
            "p": file["file_name"],
            "e": file["ext"],
            "s": fs
        })

        if file["imports"]:
            imp = ET.SubElement(f, "imp")
            for im in file["imports"]:
                if im.split('.')[0] not in mod:
                    mod.append(im.split('.')[0])
            imp.text = ",".join(mod)

        if file["functions"]:
            for func in file["functions"]:
                ET.SubElement(f, "fn", {
                    "n": func["name"],
                    "p": func["params"]
                })

        if file["classes"]:
            for clas in file["classes"]:
                cls = ET.SubElement(f, "cls", {"n": clas})
                for func in file["classes"][clas]:
                    ET.SubElement(cls, "fn", {
                        "n": func["name"],
                        "p": func["params"]
                    })

        if file["struct"]:
            ET.SubElement(f, "struct", {"n": file["struct"]})

        if file["enum"]:
            ET.SubElement(f, "enum", {"n": file["enum"]})

    out = _out_path("summary.xml")
    tree = ET.ElementTree(root)
    ET.indent(tree)
    tree.write(str(out), encoding="utf-8", xml_declaration=True)
    return out.resolve()


def gen_concat(valid,reponame):
    root = ET.Element("repo",{"n":str(reponame)})

    for file in valid:
        with open(Path(file["abspath"]).resolve(),"r",encoding="utf8") as f:
            content = f.read()
        fl = ET.SubElement(root,"file",{"n":file["relpath"]})
        src = ET.SubElement(fl,"src")
        indented = "\n".join("\t\t" + line for line in content.splitlines())
        indented = security.redact(indented)
        src.text = "\n" + indented + "\n\t"

    out = _out_path("concat.xml")
    tree = ET.ElementTree(root)
    ET.indent(tree)
    tree.write(str(out), encoding="utf-8", xml_declaration=True)
    return out.resolve()

import os
from pathlib import Path

CONFIG_DIR  = Path.home() / ".crespo"
CONFIG_FILE = CONFIG_DIR / "config"


def save_key(value: str) -> None:
    CONFIG_DIR.mkdir(exist_ok=True)
    CONFIG_FILE.write_text(f"CRESPO_GROQ_KEY={value}\n")
    try:
        CONFIG_FILE.chmod(0o600)
    except Exception:
        pass


def load_key() -> str | None:
    """Load from config file."""
    if not CONFIG_FILE.exists():
        return None
    for line in CONFIG_FILE.read_text().splitlines():
        if line.startswith("CRESPO_GROQ_KEY="):
            return line.split("=", 1)[1].strip()
    return None


def get_key(provided: str | None = None) -> str | None:
    """
    Priority:
    1. --groq flag (provided argument)
    2. CRESPO_GROQ_KEY already in system environment
    3. Saved in ~/.crespo/config

    If new key provided and differs from saved — update config.
    Always sets os.environ so summarise.py can access it directly.
    """
    saved_key = load_key()

    # resolve which key to use
    if provided:
        if provided != saved_key:
            save_key(provided)  # new key — save it
        key = provided

    elif os.environ.get("CRESPO_GROQ_KEY"):
        # already in system environment
        key = os.environ["CRESPO_GROQ_KEY"]

    elif saved_key:
        key = saved_key

    else:
        return None  # no key found anywhere

    # always inject into os.environ
    # so summarise.py can just do os.environ.get("CRESPO_GROQ_KEY")
    os.environ["CRESPO_GROQ_KEY"] = key
    return key

import argparse
import os
import sys
import time
import walker
import parse
import generate
import counter
import keystore
from pathlib import Path

# import ui — handle missing gracefully
try:
    import cli
    HAS_UI = True
except ImportError:
    HAS_UI = False

def main():
    # ── find cresbee image ────────────────────────────────────────────────────
    cresbee = None
    for p in [
        "cresbee.png",
        "assets/cresbee.png",
        str(Path(__file__).parent / "cresbee.png"),
        str(Path(__file__).parent / "assets" / "cresbee.png"),
    ]:
        if Path(p).exists():
            cresbee = p
            break

    # ── argument parsing ──────────────────────────────────────────────────────
    parser = argparse.ArgumentParser(
        prog="crespo",
        description="Crespo — Crisp repos. Sharp AI.",
        add_help=False
    )

    group = parser.add_mutually_exclusive_group()
    group.add_argument(
        "path",
        nargs="?",
        type=str,
        help="Root directory path of your codebase"
    )
    group.add_argument(
        "--git",
        type=str,
        help="GitHub URL to clone and analyse"
    )

    parser.add_argument(
        "--mode",
        choices=["structure", "summarize", "concat"],
        default="structure",
        help="Output mode (default: structure)"
    )
    parser.add_argument(
        "--output",
        type=str,
        default=None,
        help="Output filename (default: <reponame>_<mode>.xml)"
    )
    parser.add_argument(
        "--groq",
        type=str,
        default=None,
        help="Groq API key for summarize mode"
    )
    parser.add_argument(
        "--help", "-h",
        action="store_true",
        help="Show this help message"
    )

    args = parser.parse_args()

    # ── help ──────────────────────────────────────────────────────────────────
    if args.help and (args.path is None and args.git is None):
        if HAS_UI:
            cli.print_header(cresbee)
            cli.print_usage()
        else:
            parser.print_help()
        sys.exit(0)

    if args.groq and (args.path is None and args.git is None):
        saved_key = keystore.load_key()  # read stored key directly, no side effects

        if args.groq == saved_key:
            if HAS_UI:
                cli.print_info("✓ This key is already saved.")
            else:
                print("✓ This key is already saved.")
        else:
            keystore.get_key(provided=args.groq)  # saves + injects into env
            if HAS_UI:
                cli.print_info("✓ Groq key saved.")
            else:
                print("✓ Groq key saved.")
        sys.exit(0)


    if HAS_UI:
        cli.print_header(cresbee)

    start_time = time.time()
    cloned = False

    # ── resolve source FIRST ──────────────────────────────────────────────────
    if args.git:
        if HAS_UI:
            cli.print_info(f"Cloning {args.git} ...")
        try:
            import git
            import tempfile

            temp_dir = tempfile.mkdtemp()
            git.Repo.clone_from(args.git, temp_dir, depth=1, single_branch=True)
            if HAS_UI:
                cli.print_info("Clone successful\n")
            path = temp_dir
            reponame = args.git.rstrip("/").split("/")[-1].replace(".git", "")
            cloned = True
        except Exception as e:
            if HAS_UI:
                cli.print_error(f"Clone failed: {e}")
            else:
                print(f"Error: Clone failed: {e}")
            sys.exit(1)
    else:
        path = args.path
        if not os.path.exists(path):
            if HAS_UI:
                cli.print_error(f"Path '{path}' does not exist!")
            else:
                print(f"Error: Path '{path}' does not exist!")
            sys.exit(1)
        reponame = Path(path).resolve().name

    mode = args.mode

    # ── scan ──────────────────────────────────────────────────────────────────
    if HAS_UI:
        cli.print_scan_start(args.git or path, mode)
    else:
        print(f"\nRepo: {reponame}  |  Mode: {mode}\nScanning...")

    valid_files = walker.walk_dir(path=path)

    if HAS_UI:
        cli.print_tree_classic([f["relpath"] for f in valid_files], root=reponame)
    else:
        for file in valid_files:
            print(f"  ✓  {file['relpath']}")

    # ── parse ─────────────────────────────────────────────────────────────────
    if HAS_UI:
        cli.run_with_progress(valid_files, label="Parsing files")
    else:
        print(f"\nParsing {len(valid_files)} files...")

    extracted = []
    for file in valid_files:
        signature = parse.extract_struct(
            Path(file["abspath"]).resolve(),
            mode,
            file["relpath"]
        )
        extracted.append(signature)

    # ── groq key for summarize ────────────────────────────────────────────────
    if mode == "summarize":
        saved_key = keystore.load_key()
        provided_key = args.groq

        if provided_key:
            if provided_key == saved_key:
                if HAS_UI:
                    cli.print_info("✓ Using saved Groq key.")
                groq_key = provided_key
            else:
                groq_key = keystore.get_key(provided=provided_key)  # saves + injects
                if HAS_UI:
                    cli.print_info("✓ New Groq key saved.")
                else:
                    print("✓ New Groq key saved.")
        else:
            groq_key = keystore.get_key()  # checks env + saved file

        if not groq_key:
            if HAS_UI:
                cli.print_no_groq_key()
            else:
                print("Warning: No Groq key found. Falling back to structure mode.")
            mode = "structure"

    # ── security scan ─────────────────────────────────────────────────────────
    secrets_count = sum(
        1 for e in extracted
        if isinstance(e, dict) and e.get("secrets_redacted", 0) > 0
    )
    if HAS_UI:
        cli.print_security_result(secrets_count, len(valid_files))
    else:
        if secrets_count:
            print(f"Warning: {secrets_count} file(s) had secrets redacted.")

    # ── generate ──────────────────────────────────────────────────────────────
    out_path = None

    try:
        if mode == "structure":
            out_path = generate.gen_struct(extracted, reponame)
        elif mode == "summarize":
            out_path = generate.gen_summ(extracted, reponame)
        elif mode == "concat":
            out_path = generate.gen_concat(valid_files, reponame=reponame)
    except Exception as e:
        error = str(e)
        if "429" in error:
            if HAS_UI:
                cli.print_groq_fallback()
            else:
                print("Groq Limit Hit: falling back to Structure mode.")
            mode = "structure"
            out_path = generate.gen_struct(extracted, reponame)
        else:
            raise

    # override output path if --output given
    if args.output and out_path:
        import shutil as _shutil
        _shutil.move(out_path, args.output)
        out_path = args.output

    # ── token stats ───────────────────────────────────────────────────────────
    original_tokens, output_tokens = counter.tok_count(valid_files, out_path)
    elapsed = round(time.time() - start_time, 1)

    if mode == "concat":
        if HAS_UI:
            cli.print_info(
                f"Concat mode preserves full source — "
                f"output is {output_tokens:,} tokens (XML overhead included)\n"
            )
            cli.print_loc(out_path)
        else:
            print(
                f"Concat mode preserves full source — "
                f"output is {output_tokens:,} tokens (XML overhead included)\n"
                f"Blueprint saved -> {out_path}"
            )

    else:
        if HAS_UI:
            cli.print_token_stats(
                original_tokens=original_tokens,
                output_tokens=output_tokens,
                mode=mode,
                output_file=out_path or "output.xml",
                elapsed=elapsed,
            )
        else:
            reduction = round((1 - output_tokens / max(original_tokens, 1)) * 100)
            print(f"\nDone!")
            print(f"Original:  {original_tokens:,} tokens")
            print(f"Output:    {output_tokens:,} tokens")
            print(f"Reduction: {reduction}%")
            print(f"Saved to:  {out_path}")

    # ── cleanup cloned repo ───────────────────────────────────────────────────
    if cloned:
        import shutil
        shutil.rmtree(path, ignore_errors=True)


if __name__ == "__main__":
    main()

import tree_sitter_language_pack as lang_pack
import config
from pathlib import Path
from tree_sitter import QueryCursor,Parser
import security


def get_parent(node):
    CLASS_NODE_TYPES = {
        "class_definition",    # Python
        "class_declaration",   # JS, TS, Java
        "impl_item",           # Rust
    }

    ROOT_NODE_TYPES = {
        "module",              # Python
        "program",             # JS, TS
        "source_file",         # Rust, Go
        "translation_unit",    # C, C++
    }

    current = node.parent

    while current is not None:
        if current.type in CLASS_NODE_TYPES:
            name_node = current.child_by_field_name("name")

            if name_node:
                return name_node.text.decode("utf8",errors="ignore")

        if current.type in ROOT_NODE_TYPES:
            return None

        current=current.parent

    return None

def extract_body(func_node,source_bytes,ext)->str:
    if not func_node:
        return ""
    body_node = func_node.child_by_field_name("body")
    if not body_node:
        return source_bytes[func_node.start_byte:func_node.end_byte].decode("utf8",errors="ignore")

    body = source_bytes[body_node.start_byte:func_node.end_byte].decode("utf8",errors="ignore").strip()
    body = strip_body(body,ext)
    body = truncate_body(body)
    return body



def extract_struct(file,mode:str,rel_path=None):
    ext = Path(file).suffix.lower()
    configs = config.get_config()
    lang_config = configs.get(ext)

    if not lang_config:
        return {"Fallback":True}


    lang_obj  =lang_config["lang_obj"]
    parser = Parser(lang_obj)
    query = lang_obj.query(lang_config["query"])


    with open(file,encoding="utf8",errors="ignore") as f:
        source = f.read()

    source_bytes = source.encode(encoding="utf8",errors="ignore")
    tree = parser.parse(source_bytes)
    cursor = QueryCursor(query)
    captures = cursor.captures(tree.root_node)

    functions=[]
    imports=[]
    classes = {}
    struct=[]
    enum=[]

    func_nodes = sorted(
        captures.get("func_name",[]),key=lambda n:n.start_byte
    )

    param_nodes = sorted(
        captures.get("func_params",[]),key=lambda n:n.start_byte
    )

    for i,node_name in enumerate(func_nodes):
        name = node_name.text.decode("utf8",errors="ignore")

        params = ""
        if i < len(param_nodes):
            params = param_nodes[i].text.decode("utf8",errors="ignore")


        parent = get_parent(node_name)
        body = extract_body(node_name.parent,source_bytes=source_bytes,ext=ext)
        if mode =="summarize":
            body = security.redact(body)
            fn = {"name":name,"params":params,"body":body}
        else:
            fn = {"name":name,"params":params}

        if parent:
            if parent not in classes:
                classes[parent]=[]
            classes[parent].append(fn)
        else:
            functions.append(fn)  

    for capture in ["imp","imp_from","imp_source"]:
        for  node in captures.get(capture,[]):
            text=node.text.decode("utf8",errors="ignore")
            if text not in imports:
                imports.append(text)

    for capture in ["class_name","interface_name","impl_for","type_name","jsx_component"]:
        for node in captures.get(capture,[]):
            text = node.text.decode("utf8",errors="ignore")
            if text not in classes:
                classes[text]=[]

    for node in captures.get("struct_name",[]):
        text = node.text.decode("utf8",errors="ignore")
        if text not in struct:
            struct.append(text)

    for node in captures.get("enum_name",[]):
        text=node.text.decode("utf8",errors="ignore")
        if text not in enum:
            enum.append(text)

    return {"file_name":rel_path or str(file),"ext":ext,"functions":functions,"classes":classes,"imports":imports,"struct":struct,"enum":enum}



def strip_body(body: str, extension: str) -> str:
    COMMENT_CONFIG = {
    ".py": {
        "single": ["#"],
        "block": []
    },
    ".js": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".jsx": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".ts": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".tsx": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".java": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".go": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".rs": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".c": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".h": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".cpp": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
    ".hpp": {
        "single": ["//"],
        "block": [("/*", "*/")]
    },
}
    config = COMMENT_CONFIG.get(
        extension,
        {"single": ["#", "//"], "block": [("/*", "*/")]}
    )

    lines = body.splitlines()
    cleaned = []

    in_block = False
    block_end = None

    for line in lines:
        stripped = line.strip()

        if not stripped:
            continue

        # Currently inside block comment
        if in_block:
            if block_end in stripped:
                in_block = False
            continue

        # Single-line comments
        if any(stripped.startswith(marker) for marker in config["single"]):
            continue

        # Block comments
        started_block = False
        for start, end in config["block"]:
            if stripped.startswith(start):
                started_block = True

                # Multi-line block comment
                if end not in stripped[len(start):]:
                    in_block = True
                    block_end = end

                break

        if started_block:
            continue

        cleaned.append(line)

    return "\n".join(cleaned)

def truncate_body(body: str) -> str:
    lines = body.split("\n")

    if len(lines) <= 35:
        return body

    head = lines[:20]  # core logic
    tail = lines[-10:]  # return value

    return (
        "\n".join(head) +
        "\n# ...\n" +
        "\n".join(tail)
    )

from groq import Groq
import os
import cli



class Summariser():
    PROMPTS = {

        "repo": """Describe this codebase in 2 sentence max 50 words.
        Include what it does, primary stack, core features.
        Repo: {repo_name}
        Dependencies: {deps}
        Files: {files}
        Return only the summary.""",

        "file": """Describe this file's responsibility in 2-3 sentences max 50 words.
        Include what it does using technical terms,core features.
        File: {path}
        Language: {lang}
        Imports: {imports}
        Classes: {classes}
        Functions: {functions}
        Return only the summary.""",
        "files_batch": """Summarize each file below. For each write 1-2 sentences max 40 words.
            Use this format strictly:
            FILE_INDEX: <summary>
            One line per file, no extra text.

            Files:
            {files_block}

            Return only the indexed summaries.""",

        }
    def __init__(self):
            self.client = Groq(api_key=os.getenv('CRESPO_GROQ_KEY'))
            self.systemprompt = """You are an expert senior software engineer and technical writer specializing in code analysis and distillation.

                        Your task is to analyze a single file from a codebase and create a highly concise, information-dense summary optimized for LLM consumption.

                        Rules:
                        - Be extremely precise and technical
                        - Focus on purpose, responsibilities, and key implementations
                        - Never use phrases like "This file", "This module", "The code contains"
                        - Assume the reader is an experienced developer
                        - Prioritize signal over politeness
                        - Keep summaries short but information-rich

                        Output Format (strictly follow this):
                        [2 sentences maximum. Explain key responsibilities, important classes/functions, architecture decisions, and relationships with other parts of the project.]

                        Style Guidelines:
                        - Use professional but natural language
                        - Highlight important patterns (e.g., threading, real-time processing, event-driven, etc.)
                        - Mention key technologies only if they are central
                        - If the file is low value (utils, config, tests), keep DESCRIPTION very short
                            """


    def get_prompt(self,type:str,**kwargs):
        template = self.PROMPTS.get(type)
        if not template:
            raise ValueError(f"Unknown Prompt type:{type}")
        return template.format(**kwargs)

    def summarise_repo(self,repo_name,deps,files):
        userPrompt = self.get_prompt("repo",repo_name=repo_name,files = files,deps=deps)
        response = self.client.chat.completions.create(
            model="llama-3.1-8b-instant",
            messages=[{
                "role":"system",
                "content":self.systemprompt
            },
            {
                "role":"user",
                "content":userPrompt
            }],temperature=0.1,max_tokens=50
        )
        return response.choices[0].message.content.strip()

    def summarise_file(self,path,lang,imports,classes,functions):
        userPrompt = self.get_prompt("file",path=path,lang=lang,imports=imports,classes=classes,functions=functions)
        response = self.client.chat.completions.create(
            model="llama-3.1-8b-instant",
            messages=[{
                "role":"system",
                "content":self.systemprompt
            },
            {
                "role":"user",
                "content":userPrompt
            }],temperature=0.1,max_tokens=50
        )
        return response.choices[0].message.content.strip()

    def summarise_files_batch(self, files_data: list[dict]) -> list[str]:
        lines = []
        for i, f in enumerate(files_data):
            lines.append(
                f"[{i}] File: {f['path']} | Lang: {f['lang']} | "
                f"Imports: {f['imports']} | "
                f"Classes: {list(f['classes'].keys()) if f['classes'] else []} | "
                f"Functions: {[fn['name'] for fn in f['functions']] if f['functions'] else []}"
            )
        files_block = "\n".join(lines)
        user_prompt = self.get_prompt("files_batch", files_block=files_block)

        try:
            response = self.client.chat.completions.create(
                model="llama-3.1-8b-instant",
                messages=[
                    {"role": "system", "content": self.systemprompt},
                    {"role": "user",   "content": user_prompt},
                ],
                temperature=0.1,
                max_tokens=60 * len(files_data),
            )
            raw = response.choices[0].message.content.strip()
            return self._parse_batch_response(raw, len(files_data))

        except Exception as e:
            error = str(e)

            # ── token limit: split batch in half and retry ────────────────────
            if "413" in error or "too large" in error.lower() or "context" in error.lower():
                if len(files_data) == 1:
                    # can't split further — return fallback for this single file
                    return ["Summary unavailable."]
                mid = len(files_data) // 2
                left  = self.summarise_files_batch(files_data[:mid])
                right = self.summarise_files_batch(files_data[mid:])
                return left + right

            # ── rate limit: wait and retry once ──────────────────────────────
            elif "429" in error:
                import time
                time.sleep(10)
                try:
                    response = self.client.chat.completions.create(
                        model="llama-3.1-8b-instant",
                        messages=[
                            {"role": "system", "content": self.systemprompt},
                            {"role": "user",   "content": user_prompt},
                        ],
                        temperature=0.1,
                        max_tokens=60 * len(files_data),
                    )
                    raw = response.choices[0].message.content.strip()
                    return self._parse_batch_response(raw, len(files_data))
                except Exception:
                    # retry also failed — raise so gen_summ can catch and fallback to structure
                    raise

            else:
                raise


    def _parse_batch_response(self, raw: str, expected: int) -> list[str]:
        """Parse 'FILE_INDEX: summary' lines back into an ordered list."""
        results = [""] * expected
        for line in raw.splitlines():
            line = line.strip()
            if not line:
                continue
            if ":" not in line:
                continue
            idx_part, _, summary = line.partition(":")
            # handle both "FILE_0" and "0" prefixes
            idx_str = idx_part.strip().lstrip("FILE_").lstrip("FILE").strip()
            try:
                idx = int(idx_str)
                if 0 <= idx < expected:
                    results[idx] = summary.strip()
            except ValueError:
                continue
        # fill any unparsed slots with a fallback
        return [s if s else "Summary unavailable." for s in results]

import os
from pathlib import Path
import fnmatch
import config


def _load_gitignore_patterns(base_path: Path) -> list[str]:
    """
    Load all .gitignore files from base_path downward.
    Returns a flat list of patterns (relative to base_path).
    """
    patterns = []
    for root, dirs, files in os.walk(base_path):
        if ".gitignore" in files:
            gitignore = Path(root) / ".gitignore"
            rel_root = Path(root).relative_to(base_path)
            try:
                for line in gitignore.read_text(encoding="utf8", errors="ignore").splitlines():
                    line = line.strip()
                    if not line or line.startswith("#"):
                        continue
                    # prefix non-root patterns with their subdirectory
                    if str(rel_root) != ".":
                        patterns.append(str(rel_root / line))
                    else:
                        patterns.append(line)
            except Exception:
                pass
        # don't descend into ignored folders
        dirs[:] = [d for d in dirs if not d.startswith(".")]
    return patterns


def _is_gitignored(rel_path: str, patterns: list[str]) -> bool:
    """
    Return True if rel_path matches any gitignore pattern.
    Handles directory patterns (trailing /), wildcards, and negation (!).
    """
    rel = rel_path.replace("\\", "/")
    parts = Path(rel).parts

    for pattern in patterns:
        # negation — never ignore
        if pattern.startswith("!"):
            continue

        pat = pattern.rstrip("/")
        pat_unix = pat.replace("\\", "/")

        # match against full path and each suffix (so node_modules matches anywhere)
        candidates = [rel]
        for i in range(len(parts)):
            candidates.append("/".join(parts[i:]))

        for candidate in candidates:
            if fnmatch.fnmatch(candidate, pat_unix):
                return True
            # also match just the filename
            if fnmatch.fnmatch(Path(candidate).name, pat_unix):
                return True

    return False


def walk_dir(path: str, respect_gitignore: bool = True):
    IGNORE_FOLDERS = {
        ".git", ".github", ".venv", "venv", "node_modules",
        "__pycache__", ".pytest_cache", ".mypy_cache", ".tox",
        ".next", "dist", "build", "target", "site-packages",
        ".idea", ".vscode",
    }
    IGNORE_FILES = {
        "package-lock.json", "yarn.lock", ".DS_Store", ".gitignore", ".env"
    }
    CONFIG_FILES = {
        "package.json", "requirements.txt", "Cargo.toml", "go.mod", "Dockerfile"
    }

    base_path = Path(path).resolve()
    gitignore_patterns = _load_gitignore_patterns(base_path) if respect_gitignore else []

    print(f"\n Walking Directory: {path}\n")

    valid_files = []

    for root, dirs, files in os.walk(path):
        rel_root = str(Path(root).resolve().relative_to(base_path))

        # filter dirs in-place
        dirs[:] = [
            d for d in dirs
            if d not in IGNORE_FOLDERS
            and not d.startswith(".")
            and not d.startswith("_")
            and not _is_gitignored(
                str(Path(rel_root) / d) if rel_root != "." else d,
                gitignore_patterns
            )
        ]

        for file in files:
            if file in IGNORE_FILES:
                continue
            if file.startswith(".env"):
                continue

            full_path = os.path.join(root, file)
            rel_path = str(Path(full_path).resolve().relative_to(base_path))

            # check gitignore
            if respect_gitignore and _is_gitignored(rel_path, gitignore_patterns):
                continue

            isconfig = file in CONFIG_FILES
            if not isconfig and Path(file).suffix.lower() not in config.get_config():
                continue

            valid_files.append({
                "abspath":  full_path,
                "relpath":  rel_path,
                "isconfig": isconfig,
                "ext":      Path(file).suffix.lower(),
            })

    return valid_files
